mapper.select:
SELECT A.BUYER_CD , A.CONT_NUM , A.CONT_CNT , (A.MANUAL_CONT_FLAG, 0) AS MANUAL_CONT_FLAG , A.PR_BUYER_CD , A.PR_DEPT_CD , '(' A.BUYER_CD ') ' A.BUYER_NM AS BUYER_NM ,GETCUSTNAME(A.GATE_CD, A.PR_BUYER_CD) AS PR_BUYER_NM ,GETDEPTNAME(A.GATE_CD, A.PR_BUYER_CD, A.PR_DEPT_CD, #{ses.langCd}) AS PR_DEPT_NM , '(' A.PR_BUYER_CD ') ' GETBUYERDEPTNAME(A.GATE_CD, A.PR_BUYER_CD, A.PR_DEPT_CD, #{ses.langCd}) AS PR_BUYER_DEPT_NM ,GETCUSTNAME(A.GATE_CD, A.RE_BUYER_CD) AS RE_BUYER_NM ,GETDEPTNAME(A.GATE_CD, A.RE_BUYER_CD, A.RE_DEPT_CD, #{ses.langCd}) AS RE_DEPT_NM , '(' A.RE_BUYER_CD ') ' GETBUYERDEPTNAME(A.GATE_CD, A.RE_BUYER_CD, A.RE_DEPT_CD, #{ses.langCd}) AS RE_BUYER_DEPT_NM , A.CONT_USER_ID , A.CONT_USER_NM , A.CONT_DESC , A.PROGRESS_CD , A.VENDOR_CD ,(A.VENDOR_NM, GETBUYERDEPTNAME(A.GATE_CD, A.VENDOR_CD, A.VENDOR_DEPT_CD, #{ses.langCd})) AS VENDOR_NM , A.CONT_REQ_CD , A.SIGN_STATUS ,(A.CONT_DATE, 'YYYYMMDD') AS CONT_DATE ,(A.CONT_START_DATE, 'YYYYMMDD') AS CONT_START_DATE ,(A.CONT_END_DATE, 'YYYYMMDD') AS CONT_END_DATE , A.CONT_AMT_SUM , A.PR_AMT , (A.REQ_DATE, 'YYYYMMDD') AS REQ_DATE , A.CUR , A.CONT_AMT , A.VAT_TYPE ,(A.SEND_DATE, 'YYYY-MM-DD HH24:MI') AS SEND_DATE , A.FINISH_FLAG ,(A.CONT_CLOSE_DATE, 'YYYYMMDD') AS CONT_CLOSE_DATE , A.CONT_CLOSE_RMK , A.PURCHASE_TYPE , A.CONT_TYPE1 ,(CASE WHEN A.CONT_TYPE1 = 'RFQ' THEN '견적' ELSE GETCOMCODE(A.GATE_CD, 'M301', A.CONT_TYPE1, 0, #{ses.langCd}) END) AS CONT_TYPE1_TEXT , A.CONT_TYPE2 , A.FORM_NM , A.FORM_FILE_NM , A.SUB_FORM_FILE_NM , A.SIGN_PATH_NM -- 담당책임자(상신자, 결재자의 4급) , A.CONT_GROUND , A.ETC_ATT_FILE_CNT , A.ETC_ATT_FILE_NUM , A.MANAGER_RMK , A.IF_TYPE FROM (SELECT ECCT.GATE_CD , ECCT.BUYER_CD ,GETCUSTNAME(ECCT.GATE_CD, ECCT.BUYER_CD) AS BUYER_NM , ECCT.CONT_NUM , ECCT.CONT_CNT ,(CASE WHEN ECCT.MANUAL_CONT_FLAG = '0' THEN NULL ELSE ECCT.MANUAL_CONT_FLAG END) AS MANUAL_CONT_FLAG , ECCT.CONT_USER_ID ,GETUSERNAME(ECCT.GATE_CD, ECCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , ECCT.CONT_DESC , ECCT.PROGRESS_CD , ECCT.CONT_REQ_CD -- M134 , ECCT.SIGN_STATUS -- M020 , ECCT.CONT_DATE , ECCT.CONT_START_DATE , ECCT.CONT_END_DATE , ECCT.CONT_AMT AS CONT_AMT_SUM ,(SELECT SUM(B.PR_AMT) AS PR_AMT FROM (SELECT A.PR_AMT FROM (SELECT PRDT.PR_NUM, PRDT.PR_SQ, PRDT.PR_AMT FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PB_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.DEL_FLAG = '0') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0' GROUP BY PRDT.PR_NUM, PRDT.PR_SQ, PRDT.PR_AMT ) A ) B ) AS PR_AMT ,(SELECT MAX(PRHD.REQ_DATE) FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PB_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.DEL_FLAG = '0') JOIN STOCPRHD PRHD ON (PRHD.GATE_CD = PRDT.GATE_CD AND PRHD.BUYER_CD = PRDT.BUYER_CD AND PRHD.PR_NUM = PRDT.PR_NUM AND PRHD.DEL_FLAG = '0') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS REQ_DATE , ECCT.CUR -- M023 , ECCT.VAT_TYPE -- M100 , ECCT.SEND_DATE ,(CASE WHEN ECCT.CONT_END_DATE IS NOT NULL THEN '1' ELSE '0' END) AS FINISH_FLAG , ECCT.CONT_CLOSE_DATE , ECCT.CONT_CLOSE_RMK ,(CASE WHEN ECCT.MANUAL_CONT_FLAG = '1' THEN ECCM.PR_BUYER_CD ELSE ECPC.PY_BUYER_CD END) AS PR_BUYER_CD ,(CASE WHEN ECCT.MANUAL_CONT_FLAG = '1' THEN ECCM.PR_DEPT_CD ELSE ECPC.PY_DEPT_CD END) AS PR_DEPT_CD , ECCM.PR_BUYER_CD AS RE_BUYER_CD , ECCM.PR_DEPT_CD AS RE_DEPT_CD , ECCM.VENDOR_CD ,GETVENDORNAME(ECCM.GATE_CD, ECCM.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , ECCM.VENDOR_DEPT_CD ,(CASE WHEN ECCT.MANUAL_CONT_FLAG = '1' THEN ECCM.CONT_AMT ELSE ECPC.PAY_AMT END) AS CONT_AMT ,(SELECT MAX(PURCHASE_TYPE) FROM STOCECMT ECMT WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS PURCHASE_TYPE ,(SELECT MAX(CASE WHEN CNDT.RFX_TYPE = 'BID' THEN (SELECT CONT_TYPE1 FROM STOCBDHD WHERE GATE_CD = CNDT.GATE_CD AND BUYER_CD = CNDT.BUYER_CD AND BID_NUM = CNDT.BID_NUM AND BID_CNT = CNDT.BID_CNT) WHEN CNDT.RFX_TYPE = 'RFQ' THEN 'RFQ' ELSE 'PC' END) FROM STOCECMT ECMT JOIN STOCCNDT CNDT ON (CNDT.GATE_CD = ECMT.GATE_CD AND CNDT.BUYER_CD = ECMT.BUYER_CD AND CNDT.EXEC_NUM = ECMT.EXEC_NUM AND CNDT.EXEC_SQ = ECMT.EXEC_SQ) WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS CONT_TYPE1 ,(SELECT MAX(CASE WHEN CNDT.RFX_TYPE = 'BID' THEN (SELECT CONT_TYPE2 FROM STOCBDHD WHERE GATE_CD = CNDT.GATE_CD AND BUYER_CD = CNDT.BUYER_CD AND BID_NUM = CNDT.BID_NUM AND BID_CNT = CNDT.BID_CNT) WHEN CNDT.RFX_TYPE = 'RFQ' THEN 'RFQ' ELSE 'PC' END) FROM STOCECMT ECMT JOIN STOCCNDT CNDT ON (CNDT.GATE_CD = ECMT.GATE_CD AND CNDT.BUYER_CD = ECMT.BUYER_CD AND CNDT.EXEC_NUM = ECMT.EXEC_NUM AND CNDT.EXEC_SQ = ECMT.EXEC_SQ) WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS CONT_TYPE2 , ECCF.FORM_NM , ECCF.FORM_FILE_NM ,(SELECT LISTAGG('' || ECCF.FORM_FILE_NM, ',') WITHIN GROUP(ORDER BY NVL(ECCR.REL_FORM_SQ, ECRL.FORM_SQ), ECCF.FORM_FILE_NM) AS SUB_FORM_FILE_NM FROM STOCECRL ECRL JOIN STOCECCF ECCF ON (ECRL.GATE_CD = ECCF.GATE_CD AND ECRL.FORM_NUM = ECCF.FORM_NUM AND ECCF.DEL_FLAG = '0') LEFT JOIN STOCECCR ECCR ON (ECCF.GATE_CD = ECCR.GATE_CD AND ECCF.FORM_NUM = ECCR.FORM_NUM AND ECRL.FORM_NUM = ECCR.REL_FORM_NUM AND ECCR.DEL_FLAG = '0') -- 2021.01.15 : 계약서폼 중복으로 인한 오류 수정 WHERE ECRL.GATE_CD = ECCT.GATE_CD AND ECRL.BUYER_CD = ECCT.BUYER_CD AND ECRL.CONT_NUM = ECCT.CONT_NUM AND ECRL.CONT_CNT = ECCT.CONT_CNT AND ECRL.FORM_SQ > 0) AS SUB_FORM_FILE_NM ,(SELECT LISTAGG( GETDECPERSONALINFO( SIGN_PATH_NM ) ,',') WITHIN GROUP(ORDER BY SIGN_PATH_SQ) FROM ( (SELECT CVUR.USER_NM AS SIGN_PATH_NM , 1 AS SIGN_PATH_SQ FROM STOCSCTM SCTM JOIN STOCCVUR CVUR ON (CVUR.GATE_CD = SCTM.GATE_CD AND CVUR.USER_ID = SCTM.REG_USER_ID AND CVUR.POSITION_NM = '4급') -- 4급만 표시 WHERE SCTM.GATE_CD = ECCT.GATE_CD AND SCTM.APP_DOC_NUM = ECCT.APP_DOC_NUM AND SCTM.APP_DOC_CNT = ECCT.APP_DOC_CNT AND SCTM.DEL_FLAG = '0') UNION ALL (SELECT CVUR.USER_NM AS SIGN_PATH_NM , TO_NUMBER(SCTP.SIGN_PATH_SQ) + 1 AS SIGN_PATH_SQ FROM STOCSCTP SCTP JOIN STOCCVUR CVUR ON (CVUR.GATE_CD = SCTP.GATE_CD AND CVUR.USER_ID = SCTP.SIGN_USER_ID AND CVUR.POSITION_NM = '4급') -- 4급만 표시 WHERE SCTP.GATE_CD = ECCT.GATE_CD AND SCTP.APP_DOC_NUM = ECCT.APP_DOC_NUM AND SCTP.APP_DOC_CNT = ECCT.APP_DOC_CNT AND SCTP.DEL_FLAG = '0') ) WHERE 1 = 1) AS SIGN_PATH_NM ,(SELECT MAX(PRDT.CONT_GROUND) FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PR_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.CONT_GROUND IS NOT NULL) WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS CONT_GROUND , ECCT.ETC_ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = ECCT.GATE_CD AND UUID = ECCT.ETC_ATT_FILE_NUM AND DEL_FLAG = '0') AS ETC_ATT_FILE_CNT , ECCT.MANAGER_RMK ,(SELECT MAX(PRHD.IF_TYPE) FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PB_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.DEL_FLAG = '0') JOIN STOCPRHD PRHD ON (PRHD.GATE_CD = PRDT.GATE_CD AND PRHD.BUYER_CD = PRDT.BUYER_CD AND PRHD.PR_NUM = PRDT.PR_NUM AND PRHD.IF_TYPE IS NOT NULL AND PRHD.DEL_FLAG = '0') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS IF_TYPE FROM STOCECCT ECCT JOIN STOCECCM ECCM ON (ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0') LEFT JOIN STOCECRL ECRL ON (ECRL.GATE_CD = ECCT.GATE_CD AND ECRL.BUYER_CD = ECCT.BUYER_CD AND ECRL.CONT_NUM = ECCT.CONT_NUM AND ECRL.CONT_CNT = ECCT.CONT_CNT AND ECRL.FORM_SQ = '0' AND ECRL.DEL_FLAG = '0') LEFT JOIN STOCECCF ECCF ON (ECCF.GATE_CD = ECRL.GATE_CD AND ECCF.FORM_NUM = ECRL.FORM_NUM AND ECCF.CONT_TYPE IN ('1110', '1130', '1210') AND ECCF.DEL_FLAG = '0') LEFT JOIN STOCECPC ECPC ON (ECPC.GATE_CD = ECCM.GATE_CD AND ECPC.BUYER_CD = ECCM.BUYER_CD AND ECPC.CONT_NUM = ECCM.CONT_NUM AND ECPC.CONT_CNT = ECCM.CONT_CNT AND ECPC.PR_BUYER_CD = ECCM.PR_BUYER_CD AND ECPC.PR_DEPT_CD = ECCM.PR_DEPT_CD AND ECPC.VENDOR_CD = ECCM.VENDOR_CD AND ECPC.PAY_CNT = 0 AND ECPC.DEL_FLAG = '0') WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.PROGRESS_CD = '4300' -- 계약완료 AND ECCT.BUNDLE_NUM IS NULL -- 다수계약서 제외(다수계약서는 구매의뢰로 진행하지 않음) AND ECCT.DEL_FLAG = '0' AND ECCT.BUYER_CD = #{ses.companyCd}
AND ECCT.CONT_DATE >= (#{REG_DATE_FROM}) AND ECCT.CONT_DATE <= (#{REG_DATE_TO})
AND ECCT.CONT_END_DATE >= (#{REG_DATE_FROM}) AND ECCT.CONT_END_DATE <= (#{REG_DATE_TO})
AND ((ECCT.BUYER_CD LIKE '%' UPPER(#{PR_BUYER_CD}) '%') OR (ECCM.PR_BUYER_CD LIKE '%' UPPER(#{PR_BUYER_CD}) '%') OR (ECPC.PY_BUYER_CD LIKE '%' UPPER(#{PR_BUYER_CD}) '%') )
AND ((UPPER(GETCUSTNAME(ECCT.GATE_CD, ECCT.BUYER_CD)) LIKE '%' UPPER(#{PR_BUYER_NM}) '%') OR (UPPER(GETCUSTNAME(ECCM.GATE_CD, ECCM.PR_BUYER_CD)) LIKE '%' UPPER(#{PR_BUYER_NM}) '%') OR (UPPER(GETCUSTNAME(ECPC.GATE_CD, ECPC.PY_BUYER_CD)) LIKE '%' UPPER(#{PR_BUYER_NM}) '%') )
AND ECCM.VENDOR_CD LIKE '%' UPPER(#{VENDOR_CD}) '%'
AND UPPER(GETVENDORNAME(ECCM.GATE_CD, ECCM.VENDOR_CD, #{ses.langCd})) LIKE '%' UPPER(#{VENDOR_NM}) '%'
AND ((ECCT.CONT_USER_ID LIKE '%' UPPER(#{CONT_USER_ID}) '%') OR (ECPC.PY_USER_ID LIKE '%' UPPER(#{CONT_USER_ID}) '%') )
AND ((UPPER(GETUSERNAME(ECCT.GATE_CD, ECCT.CONT_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{CONT_USER_NM}) '%') OR (UPPER(GETUSERNAME(ECPC.GATE_CD, ECPC.PY_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{CONT_USER_NM}) '%') )
AND ((UPPER(REPLACE(ECCT.CONT_DESC, ' ', '')) LIKE '%' UPPER(REPLACE(#{CONT_NUM}, ' ', '')) '%') OR (ECCT.CONT_NUM LIKE '%' UPPER(#{CONT_NUM}) '%') )
AND ECCT.PROGRESS_CD IN
#{item}
AND ECCT.CONT_REQ_CD = #{CONT_REQ_CD}
) A WHERE 1 = 1
AND UPPER(A.SIGN_PATH_NM) LIKE '%' UPPER(#{SIGN_PATH_NM}) '%'
AND A.PURCHASE_TYPE = #{PURCHASE_TYPE}
AND A.CONT_TYPE1 = #{CONT_TYPE1}
AND A.CONT_TYPE2 = #{CONT_TYPE2}
AND UPPER(A.FORM_NM) LIKE '%' UPPER(#{FORM_NM}) '%'
ORDER BY A.CONT_NUM DESC , A.CONT_CNT DESC

mapper.update:
UPDATE STOCECCT
   SET ETC_ATT_FILE_NUM = #{ETC_ATT_FILE_NUM}
	 , MANAGER_RMK = #{MANAGER_RMK}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND DEL_FLAG = '0'
